const body = $json.body || $json;

const jobDescription = body.jobDescription || '';
const baseResume    = body.baseResume    || '';
const recipientEmail = body.recipientEmail || 'rvnegi786@gmail.com';

if (!jobDescription) throw new Error('jobDescription is required in the request body');
if (!baseResume)     throw new Error('baseResume is required in the request body');

return {
  jobDescription,
  baseResume,
  recipientEmail
};

function cleanText(t) {
  return (t || '').replace(/```[a-z]*\n?/gi, '').replace(/```/g, '').trim();
}
function esc(s) {
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
}
function md2html(s) {
  // Convert markdown-style **bold** tags to HTML bold tags
  return esc(s).replace(/\*\*(.*?)\*\*/g, '<b>$1</b>');
}

const resumeText = cleanText($('Generate Tailored Resume').item.json.text || '');
const meta = $('Prepare Input').item.json;
const recipientEmail = meta.recipientEmail || 'rvnegi786@gmail.com';
const dateStr = new Date().toLocaleDateString('en-IN', { day:'2-digit', month:'short', year:'numeric' });
const jdPreview = (meta.jobDescription || '').substring(0, 100).replace(/\n/g,' ').trim();

const SECTIONS = ['PROFESSIONAL SUMMARY','TECHNICAL SKILLS','PROFESSIONAL EXPERIENCE',
  'WORK EXPERIENCE','EXPERIENCE','PROJECTS','AWARDS','EDUCATION','SKILLS'];

const lines = resumeText.split('\n');
let name='', contactLine='', linksLine='';
let sections={}, currentSection='', sectionContent=[];

for (let i = 0; i < lines.length; i++) {
  const line = lines[i].trim();
  if (!line) continue;
  if (i === 0) { name = line; continue; }
  if (i === 1) { contactLine = line.replace(/\|/g, ' — '); continue; }
  if (i === 2 && (line.toLowerCase().includes('linkedin') || line.toLowerCase().includes('github'))) {
    linksLine = line; continue;
  }
  const upper = line.toUpperCase();
  const isSection = SECTIONS.some(s => upper.startsWith(s));
  if (isSection) {
    if (currentSection) sections[currentSection] = [...sectionContent];
    currentSection = SECTIONS.find(s => upper.startsWith(s));
    sectionContent = [];
  } else {
    if (currentSection) sectionContent.push(line);
  }
}
if (currentSection) sections[currentSection] = [...sectionContent];

const dateStr2 = new Date().toLocaleDateString('en-IN', { day:'2-digit', month:'short', year:'numeric' });
const jdPreview2 = (meta.jobDescription || '').substring(0, 100).replace(/\n/g,' ').trim();

const emailBody = `<div style="font-family:Arial,sans-serif;max-width:560px;margin:0 auto;">
<div style="background:linear-gradient(135deg,#7c3aed,#4f46e5,#06b6d4);padding:28px 32px;border-radius:10px 10px 0 0;text-align:center;">
